\n    terminals.delete(id);\n    return true;\n  }\n\n  function list() {\n    return Array.from(terminals.values()).map(function (session) {\n      return {\n        id: session.id,\n        cols: session.cols,\n        rows: session.rows,\n        closed: session.closed\n      };\n    });\n  }\n\n  return {\n    create: create,\n    write: write,\n    resize: resize,\n    close: close,\n    list: list\n  };\n}\n\nmodule.exports = {\n  createTerminalManager\n};\n"
